import { defineConfig, devices } from '@playwright/test';

/**
 * Playwright configuration for OurPot QA testing
 *
 * SCOPE: Chrome Desktop + Android Mobile ONLY
 * See PROJECT_SCOPE.md for full testing constraints
 *
 * @see https://playwright.dev/docs/test-configuration
 */
export default defineConfig({
  testDir: './tests',
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 1,
  workers: process.env.CI ? 1 : undefined,
  reporter: [
    ['html'],
    ['list'],
  ],

  use: {
    // Base URL from environment or default to preview
    baseURL: process.env.BASE_URL || 'https://our-pot-app-git-develop-kimwongwwk-gmailcoms-projects.vercel.app',

    // Collect trace when retrying the failed test
    trace: 'on-first-retry',

    // Capture screenshot on failure
    screenshot: 'only-on-failure',

    // Record video on failure
    video: 'retain-on-failure',
  },

  // Timeouts per PROJECT_SCOPE.md
  timeout: 30000, // 30s for AI operations
  expect: {
    timeout: 5000, // 5s for UI assertions
  },

  /**
   * Browser Matrix (Current Phase):
   * - Desktop Chrome: Primary browser
   * - Mobile Android: Pixel 5 viewport
   *
   * NOT included (per PROJECT_SCOPE.md):
   * - Firefox, Safari, Edge, iOS
   */
  projects: [
    {
      name: 'desktop-chrome',
      use: {
        ...devices['Desktop Chrome'],
        viewport: { width: 1280, height: 720 },
      },
    },
    {
      name: 'mobile-android',
      use: {
        ...devices['Pixel 5'],
      },
    },
    // iOS Safari - OUT OF SCOPE for current phase
    // {
    //   name: 'mobile-safari',
    //   use: { ...devices['iPhone 12'] },
    // },
  ],

  // Output folder for test artifacts
  outputDir: 'test-results/',
});

